import { Inference, Page } from "../../../v1/parsing/common/index.js";
import { FinancialDocumentV1Document } from "./financialDocumentV1Document.js";
/**
 * Financial Document API version 1 inference prediction.
 */
export class FinancialDocumentV1 extends Inference {
    constructor(rawPrediction) {
        super(rawPrediction);
        /** The endpoint's name. */
        this.endpointName = "financial_document";
        /** The endpoint's version. */
        this.endpointVersion = "1";
        /** The document's pages. */
        this.pages = [];
        this.prediction = new FinancialDocumentV1Document(rawPrediction["prediction"]);
        rawPrediction["pages"].forEach((page) => {
            if (page.prediction !== undefined && page.prediction !== null &&
                Object.keys(page.prediction).length > 0) {
                this.pages.push(new Page(FinancialDocumentV1Document, page, page["id"], page["orientation"]));
            }
        });
    }
}
